-- create "snapshot_rates" table
CREATE TABLE "snapshot_rates" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 68719476736), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "rate" numeric(36,18) NOT NULL, "from_currency_id" bigint NOT NULL, "to_currency_id" bigint NOT NULL, "snapshot_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "snapshot_rates_currencies_snapshot_rates_from" FOREIGN KEY ("from_currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "snapshot_rates_currencies_snapshot_rates_to" FOREIGN KEY ("to_currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "snapshot_rates_snapshots_snapshot_rates" FOREIGN KEY ("snapshot_id") REFERENCES "snapshots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "snapshotrate_snapshot_id" to table: "snapshot_rates"
CREATE INDEX "snapshotrate_snapshot_id" ON "snapshot_rates" ("snapshot_id");
-- create index "snapshotrate_snapshot_id_from_currency_id_to_currency_id" to table: "snapshot_rates"
CREATE UNIQUE INDEX "snapshotrate_snapshot_id_from_currency_id_to_currency_id" ON "snapshot_rates" ("snapshot_id", "from_currency_id", "to_currency_id");
